1	import {
2	  isRejection,
3	  PluginError,
4	  type AgentContext,
5	  type HookBus,
6	} from '@ax/core';
7	import type { ChunkBuffer } from './chunk-buffer.js';
8	import type { PhaseEvent, SseFrame, StreamChunk } from './types.js';
9	
10	// ---------------------------------------------------------------------------
11	// SSE handler factory.
12	//
13	// Wires GET /api/chat/stream/:reqId. Per request:
14	//
15	//   1. auth:require-user → 401 on rejection.
16	//   2. conversations:get-by-req-id → 404 (NOT 403) on not-found.
17	//      404-not-403 is intentional (J9): we don't tell foreign callers
18	//      whether a reqId exists at all.
19	//   3. agents:resolve(agentId, userId) → 404 same posture as above.
20	//   4. Open the stream, replay the buffer's current chunks for this
21	//      reqId, then attach BOTH a `chat:stream-chunk` subscriber (filtered
22	//      by reqId) AND a `chat:turn-end` subscriber (filtered by
23	//      conversationId). The chunk subscriber emits one `data:` frame
24	//      per chunk; the turn-end subscriber emits a final `done: true`
25	//      and closes.
26	//
27	// Subscribers are unwired on:
28	//   - `done: true` emitted (turn-end)
29	//   - client disconnect (res.stream's onClose)
30	//
31	// Keepalive: a 25 s `:\n\n` heartbeat keeps the connection alive through
32	// proxies that idle-cull. The sweep is a SINGLE setInterval per
33	// connection; cleared in onClose.
34	// ---------------------------------------------------------------------------
35	
36	const SSE_KEEPALIVE_MS = 25_000;
37	
38	// Duck-typed request/response. The full @ax/http-server `HttpResponse` adds
39	// `stream()` (we extended it for this slice); we re-declare just the
40	// piece we need so this file stays free of @ax/http-server imports
41	// (Invariant I2).
42	export interface RouteRequest {
43	  readonly headers: Record<string, string>;
44	  readonly body: Buffer;
45	  readonly cookies: Record<string, string>;
46	  readonly query: Record<string, string>;
47	  readonly params: Record<string, string>;
48	  signedCookie(name: string): string | null;
49	}
50	
51	export interface RouteStream {
52	  write(chunk: string | Buffer): void;
53	  close(): void;
54	  onClose(handler: () => void): void;
55	}
56	
57	export interface RouteResponse {
58	  status(n: number): RouteResponse;
59	  header(name: string, value: string): RouteResponse;
60	  json(v: unknown): void;
61	  text(s: string): void;
62	  end(): void;
63	  stream(opts?: { contentType?: string }): RouteStream;
64	}
65	
66	export interface SseHandlerDeps {
67	  bus: HookBus;
68	  initCtx: AgentContext;
69	  buffer: ChunkBuffer;
70	}
71	
72	/**
73	 * Build the GET /api/chat/stream/:reqId handler. The SSE handler factory
74	 * also returns the bus subscriber the channel-web plugin needs to attach
75	 * to `chat:stream-chunk` so the buffer fills as chunks arrive — this
76	 * keeps subscriber + handler in one file (the handler reads from the
77	 * same buffer).
78	 */
79	export function createSseHandler(deps: SseHandlerDeps) {
80	  const PLUGIN_NAME = '@ax/channel-web';
81	
82	  /** Helper — format a single frame as a complete SSE event line. */
83	  function formatFrame(frame: SseFrame): string {
84	    // Newlines inside JSON.stringify output are escaped; \n separators
85	    // delimit the SSE event. The browser EventSource splits on \n\n.
86	    return `data: ${JSON.stringify(frame)}\n\n`;
87	  }
88	
89	  return async function handle(
90	    req: RouteRequest,
91	    res: RouteResponse,
92	  ): Promise<void> {
93	    // 1) Authenticate.
94	    let userId: string;
95	    try {
96	      const result = await deps.bus.call<
97	        { req: RouteRequest },
98	        { user: { id: string; isAdmin: boolean } }
99	      >('auth:require-user', deps.initCtx, { req });
100	      userId = result.user.id;
101	    } catch (err) {
102	      // Both PluginError('unauthenticated') and bus.fire-style rejections
103	      // collapse to 401 — the route is closed by default.
104	      if (err instanceof PluginError || isRejection(err)) {
105	        res.status(401).json({ error: 'unauthenticated' });
106	        return;
107	      }
108	      throw err;
109	    }
110	
111	    // 2) Resolve the reqId → conversation (J9 — server-derived ACL).
112	    const reqId = req.params.reqId;
113	    if (typeof reqId !== 'string' || reqId.length === 0) {
114	      // Same 404 posture as a missing row — the URL didn't shape into
115	      // a conversation we own.
116	      res.status(404).json({ error: 'not-found' });
117	      return;
118	    }
119	    let conversationId: string;
120	    let agentId: string;
121	    try {
122	      const conv = await deps.bus.call<
123	        { reqId: string; userId: string },
124	        {
125	          conversationId: string;
126	          agentId: string;
127	          userId: string;
128	          activeReqId: string | null;
129	        }
130	      >('conversations:get-by-req-id', deps.initCtx, { reqId, userId });
131	      conversationId = conv.conversationId;
132	      agentId = conv.agentId;
133	    } catch (err) {
134	      // not-found OR forbidden OR anything else from the lookup → 404.
135	      // We deliberately collapse to the same code so callers can't tell
136	      // "your reqId doesn't exist" from "you don't own it" (J9).
137	      if (err instanceof PluginError) {
138	        res.status(404).json({ error: 'not-found' });
139	        return;
140	      }
141	      throw err;
142	    }
143	
144	    // 3) ACL the conversation's agent against the calling user. Same
145	    // 404-not-403 posture: an agent the user can no longer reach
146	    // shouldn't even confirm the conversation is theirs.
147	    try {
148	      await deps.bus.call<
149	        { agentId: string; userId: string },
150	        unknown
151	      >('agents:resolve', deps.initCtx, { agentId, userId });
152	    } catch (err) {
153	      if (err instanceof PluginError) {
154	        res.status(404).json({ error: 'not-found' });
155	        return;
156	      }
157	      throw err;
158	    }
159	
160	    // 4) Open the SSE stream. From here on we own the response — write
161	    // failures and exceptions degrade to a quiet close.
162	    const stream = res.status(200).stream({
163	      contentType: 'text/event-stream; charset=utf-8',
164	    });
165	
166	    let closed = false;
167	    let keepaliveTimer: ReturnType<typeof setInterval> | null = null;
168	
169	    // Subscriber keys are unique per connection so multiple SSE
170	    // listeners on the same reqId (multi-tab) each get their own
171	    // subscription instead of fighting over a shared one. Mixing in
172	    // crypto-random isn't strictly needed (the bus uses the key only
173	    // for unsubscribe), but it keeps two opens on the same reqId
174	    // cleanly distinguishable in logs.
175	    const subscriberSuffix = `${reqId}-${Math.random().toString(36).slice(2, 10)}`;
176	    const chunkSubKey = `${PLUGIN_NAME}/sse-chunk/${subscriberSuffix}`;
177	    const phaseSubKey = `${PLUGIN_NAME}/sse-phase/${subscriberSuffix}`;
178	    const turnEndSubKey = `${PLUGIN_NAME}/sse-turn-end/${subscriberSuffix}`;
179	
180	    const cleanup = (): void => {
181	      if (closed) return;
182	      closed = true;
183	      if (keepaliveTimer !== null) {
184	        clearInterval(keepaliveTimer);
185	        keepaliveTimer = null;
186	      }
187	      // unsubscribe is idempotent if no match — safe to call even when a
188	      // subscriber was never registered (e.g. error in setup).
189	      deps.bus.unsubscribe('chat:stream-chunk', chunkSubKey);
190	      deps.bus.unsubscribe('chat:phase', phaseSubKey);
191	      deps.bus.unsubscribe('chat:turn-end', turnEndSubKey);
192	    };
193	
194	    stream.onClose(() => {
195	      cleanup();
196	    });
197	
198	    const safeWrite = (frame: SseFrame): void => {
199	      if (closed) return;
200	      try {
201	        stream.write(formatFrame(frame));
202	      } catch {
203	        cleanup();
204	        try {
205	          stream.close();
206	        } catch {
207	          // already closed
208	        }
209	      }
210	    };
211	
212	    // 4a) Replay the existing buffer BEFORE attaching the live
213	    // subscriber. If we attached the subscriber first and THEN drained,
214	    // a chunk that fired in between would arrive twice (once via the
215	    // subscriber, once via the buffer drain). If we drained first and
216	    // THEN attached, a chunk fired in between would be lost. We do
217	    // drain-first because the bus runs subscribers serially: the
218	    // subscribe call below executes synchronously after this drain,
219	    // and bus.fire() can't interleave with the same async tick (it
220	    // awaits each subscriber). The narrow window where a chunk lands
221	    // in the buffer DURING the drain is harmless because we re-snapshot
222	    // a copy via `tail()`, so any concurrent appends are visible to
223	    // the subscriber pass that follows.
224	    //
225	    // Phase replays first — it's "before content" by construction (the
226	    // buffer evicts phase as soon as a content chunk lands), so emitting
227	    // it ahead of the chunks matches the order the original turn fired.
228	    const replayPhase = deps.buffer.tailPhase(reqId);
229	    if (replayPhase !== null) {
230	      safeWrite({ reqId, phase: replayPhase });
231	    }
232	    const replay = deps.buffer.tail(reqId);
233	    for (const chunk of replay) {
234	      // The chunk *is* a valid SseFrame variant — types align by design.
235	      safeWrite(chunk);
236	    }
237	
238	    // 4b) Attach the live chunk subscriber. Filter by reqId so multiple
239	    // in-flight conversations sharing the same host don't bleed.
240	    deps.bus.subscribe<StreamChunk>(
241	      'chat:stream-chunk',
242	      chunkSubKey,
243	      async (_ctx, payload) => {
244	        if (payload.reqId !== reqId) return undefined;
245	        safeWrite(payload);
246	        // Subscribers are observation-only here; we never reject or
247	        // mutate. Returning undefined means "pass through".
248	        return undefined;
249	      },
250	    );
251	
252	    // 4b-bis) Attach the live phase subscriber. Same filter posture as
253	    // chunks; subscribers are observation-only and never veto.
254	    deps.bus.subscribe<PhaseEvent>(
255	      'chat:phase',
256	      phaseSubKey,
257	      async (_ctx, payload) => {
258	        if (payload.reqId !== reqId) return undefined;
259	        safeWrite({ reqId: payload.reqId, phase: payload.phase });
260	        return undefined;
261	      },
262	    );
263	
264	    // 4c) Attach the turn-end subscriber. Filter by ctx.conversationId
265	    // so a turn-end on a different conversation doesn't close us out.
266	    deps.bus.subscribe<{ reqId?: string; reason?: string }>(
267	      'chat:turn-end',
268	      turnEndSubKey,
269	      async (ctx, _payload) => {
270	        if (ctx.conversationId !== conversationId) return undefined;
271	        // Emit the done frame, evict the buffer (this turn is over),
272	        // then close. The eviction here is the success path; the TTL
273	        // sweep in chunk-buffer is the fallback for browsers that
274	        // never get here (closed mid-stream).
275	        safeWrite({ reqId, done: true });
276	        deps.buffer.evictReqId(reqId);
277	        cleanup();
278	        try {
279	          stream.close();
280	        } catch {
281	          // already closed
282	        }
283	        return undefined;
284	      },
285	    );
286	
287	    // 4d) Keepalive. The SSE comment ":\n\n" is silently dropped by
288	    // EventSource but keeps proxies (and the http-server's idle
289	    // timeout) from culling the connection. setInterval handle is
290	    // unref'd so a hung connection doesn't block process exit.
291	    keepaliveTimer = setInterval(() => {
292	      if (closed) return;
293	      try {
294	        stream.write(':\n\n');
295	      } catch {
296	        cleanup();
297	      }
298	    }, SSE_KEEPALIVE_MS);
299	    if (typeof (keepaliveTimer as { unref?: () => void }).unref === 'function') {
300	      (keepaliveTimer as { unref: () => void }).unref();
301	    }
302	
303	    // Handler returns now; the stream lives on until cleanup fires.
304	  };
305	}
306	
307	/**
308	 * Subscriber the plugin attaches at boot to fill the chunk buffer. Lives
309	 * here (not in plugin.ts) so the buffer + write-path stay in one file —
310	 * the SSE handler's `tail()` drain depends on it.
311	 */
312	export function createBufferFillSubscriber(buffer: ChunkBuffer) {
313	  return async function (
314	    _ctx: AgentContext,
315	    payload: StreamChunk,
316	  ): Promise<undefined> {
317	    // Defensive: a malformed event from the bus shouldn't tear down the
318	    // host. The schema validation already happened in the IPC handler
319	    // (Task 5); this is belt-and-braces.
320	    if (typeof payload?.reqId !== 'string' || typeof payload?.kind !== 'string') {
321	      return undefined;
322	    }
323	    if (payload.kind === 'text' || payload.kind === 'thinking') {
324	      if (typeof (payload as { text?: unknown }).text !== 'string') {
325	        return undefined;
326	      }
327	      buffer.append(payload as StreamChunk);
328	      return undefined;
329	    }
330	    if (payload.kind === 'tool-use') {
331	      const p = payload as {
332	        toolCallId?: unknown;
333	        toolName?: unknown;
334	        input?: unknown;
335	      };
336	      if (
337	        typeof p.toolCallId !== 'string' ||
338	        typeof p.toolName !== 'string' ||
339	        typeof p.input !== 'object' ||
340	        p.input === null ||
341	        Array.isArray(p.input)
342	      ) {
343	        return undefined;
344	      }
345	      buffer.append(payload as StreamChunk);
346	      return undefined;
347	    }
348	    if (payload.kind === 'tool-result') {
349	      const p = payload as {
350	        toolCallId?: unknown;
351	        output?: unknown;
352	        isError?: unknown;
353	      };
354	      if (
355	        typeof p.toolCallId !== 'string' ||
356	        typeof p.output !== 'string' ||
357	        (p.isError !== undefined && typeof p.isError !== 'boolean')
358	      ) {
359	        return undefined;
360	      }
361	      buffer.append(payload as StreamChunk);
362	      return undefined;
363	    }
364	    return undefined;
365	  };
366	}
367	
368	/**
369	 * Sister to `createBufferFillSubscriber`, but for `chat:phase`. Captures
370	 * the latest phase per reqId so an SSE handler attaching after the phase
371	 * fired still sees it on replay.
372	 */
373	export function createPhaseFillSubscriber(buffer: ChunkBuffer) {
374	  return async function (
375	    _ctx: AgentContext,
376	    payload: PhaseEvent,
377	  ): Promise<undefined> {
378	    if (
379	      typeof payload?.reqId !== 'string' ||
380	      payload.reqId.length === 0 ||
381	      payload?.phase !== 'sandbox-starting'
382	    ) {
383	      return undefined;
384	    }
385	    buffer.appendPhase(payload.reqId, payload.phase);
386	    return undefined;
387	  };
388	}
389	
390	/**
391	 * Turn-end subscriber the plugin attaches at boot. Pre-evicts the buffer
392	 * for reqIds that ended successfully so the per-connection turn-end
393	 * subscriber is the only path that needs to fire the done frame. Lives
394	 * here for the same one-file reason as the chunk filler.
395	 *
396	 * NOTE: this subscriber MUST NOT close any per-connection streams — it
397	 * runs on the host bus and doesn't know about the SSE handlers. Per-
398	 * connection turn-end handling is inside `createSseHandler` and matches
399	 * `ctx.conversationId`. We keep this subscriber separate because a
400	 * conversation may end without any SSE listener attached, and the
401	 * buffer should still be cleaned up.
402	 */
403	export function createTurnEndEvictor(buffer: ChunkBuffer) {
404	  return async function (
405	    _ctx: AgentContext,
406	    payload: { reqId?: string },
407	  ): Promise<undefined> {
408	    if (typeof payload?.reqId === 'string' && payload.reqId.length > 0) {
409	      buffer.evictReqId(payload.reqId);
410	    }
411	    return undefined;
412	  };
413	}
414

