1	/**
2	 * AxChatTransport — speaks the AX-native chat-flow producer / SSE wire.
3	 *
4	 * Two-phase exchange replacing the OpenAI-SSE stub used during early
5	 * prototyping (Tasks 9-13 froze the wire shapes in src/wire/chat.ts):
6	 *
7	 *   1. POST /api/chat/messages with `{ conversationId | null, agentId,
8	 *      contentBlocks }`. The handler validates + ACL-gates, mints a
9	 *      server-side `reqId` (J9 — never client-supplied), and replies
10	 *      202 with `{ conversationId, reqId }`.
11	 *
12	 *   2. Open `EventSource('/api/chat/stream/' + reqId)` (we use a
13	 *      fetch-based SSE reader so we keep the same protected
14	 *      `processResponseStream` hook the AI SDK gives us). Each
15	 *      `data:` line is a JSON-encoded `SseFrame`:
16	 *
17	 *        - `{ reqId, text, kind: 'text' | 'thinking' }` — content delta.
18	 *          We stream `kind === 'text'` chunks as `text-delta` UIMessage-
19	 *          Chunks under id `text-N`. `kind === 'thinking'` chunks are
20	 *          emitted under a separate id `thinking-N` so the per-message
21	 *          toggle (Task 21) can hide them.
22	 *
23	 *        - `{ reqId, done: true }` — terminator. We close the open part(s)
24	 *          and emit a `finish` UIMessageChunk (`finishReason: 'stop'`).
25	 *
26	 * Wire-shape source of truth: `src/server/types.ts` (`SseFrame`) +
27	 * `src/wire/chat.ts` (`PostMessageRequest` / `PostMessageResponse`).
28	 *
29	 * Boundary review (I1-I5):
30	 *   - I1: field names — conversationId / agentId / reqId / contentBlocks /
31	 *     text / kind / done — are LLM-API vocab, not transport/storage vocab.
32	 *   - I2: this file imports only from `ai` (the AI SDK transport base) and
33	 *     `@ax/ipc-protocol` (ContentBlock type). No cross-plugin reach.
34	 *   - I3: full chain (POST → SSE → UIMessageChunks → render) lands in
35	 *     this PR.
36	 *   - I4: conversationId returned by POST is captured in `conversationRef`
37	 *     so the next user turn re-uses it (the conversation row is the source
38	 *     of truth — Task 10's GET /api/chat/conversations/:id reads from it).
39	 *   - I5: `text` in incoming SSE frames is UNTRUSTED model output; it
40	 *     flows through the AI SDK text-delta pipeline and is rendered by
41	 *     <MarkdownText /> via react-markdown's safe defaults (no rehypeRaw,
42	 *     no raw-HTML escape hatches enabled).
43	 */
44	
45	import type { ContentBlock } from '@ax/ipc-protocol';
46	import { HttpChatTransport, type UIMessage, type UIMessageChunk } from 'ai';
47	import { agentStatusActions } from './agent-status-store';
48	
49	const DEFAULT_USER = 'guest';
50	
51	/**
52	 * Map a wire phase value to the user-facing label. Centralized here so
53	 * future i18n is one switch (and adding a phase doesn't require changing
54	 * the parser). Returning `null` means "unknown phase" — we ignore it
55	 * rather than render a half-baked default; forward-compat with newer
56	 * server builds that emit a phase the client doesn't yet recognize.
57	 */
58	const PHASE_LABELS: Record<string, string> = {
59	  'sandbox-starting': 'Starting sandbox…',
60	};
61	
62	/** Shape of one SSE `data:` JSON payload. Matches `SseFrame` in src/server/types.ts. */
63	type SseFrame =
64	  | { reqId: string; kind: 'text'; text: string }
65	  | { reqId: string; kind: 'thinking'; text: string }
66	  | {
67	      reqId: string;
68	      kind: 'tool-use';
69	      toolCallId: string;
70	      toolName: string;
71	      input: Record<string, unknown>;
72	    }
73	  | {
74	      reqId: string;
75	      kind: 'tool-result';
76	      toolCallId: string;
77	      output: string;
78	      isError?: boolean;
79	    }
80	  | { reqId: string; phase: string }
81	  | { reqId: string; done: true };
82	
83	interface AxChatTransportOptions {
84	  /**
85	   * Endpoint to POST user messages to. Defaults to `/api/chat/messages`
86	   * which the host plugin registers; tests can pin to a different mount.
87	   */
88	  api?: string;
89	  /**
90	   * Endpoint prefix for the SSE subscription. Suffixed with the minted
91	   * reqId. Defaults to `/api/chat/stream`; the chat-flow plugin mounts
92	   * `/api/chat/stream/:reqId` (with the trailing slash).
93	   */
94	  streamApi?: string;
95	  /**
96	   * Logical user id — purely for the legacy `user` body field, kept here
97	   * so the runtime hook contract doesn't break. The new wire doesn't
98	   * carry it (auth lives in the cookie); we accept + ignore it.
99	   */
100	  user?: string;
101	  /**
102	   * Optional resolver for the active conversationId. The transport will
103	   * read this BEFORE every send and write the server-returned id back via
104	   * `setConversationId`. If not provided, transport-internal state is the
105	   * source.
106	   */
107	  getConversationId?: () => string | null;
108	  setConversationId?: (id: string) => void;
109	  /**
110	   * Resolver for which agent the user is messaging. The wire requires it
111	   * (PostMessageRequest.agentId is non-empty). The runtime hook reads the
112	   * agent-store and provides this.
113	   */
114	  getAgentId?: () => string | null;
115	  /**
116	   * Custom fetch — primarily for tests so they can mock the POST without
117	   * a global override.
118	   */
119	  fetch?: typeof fetch;
120	}
121	
122	const AX_ATTACHMENT_URL_PREFIX = 'ax://attachment/';
123	
124	function isAxAttachmentPart(p: unknown): { attachmentId: string } | null {
125	  if (!p || typeof p !== 'object') return null;
126	  const obj = p as { type?: unknown; data?: unknown; url?: unknown };
127	  if (obj.type !== 'file') return null;
128	  const candidate =
129	    typeof obj.data === 'string' ? obj.data :
130	    typeof obj.url === 'string' ? obj.url : null;
131	  if (candidate === null) return null;
132	  if (!candidate.startsWith(AX_ATTACHMENT_URL_PREFIX)) return null;
133	  const id = candidate.slice(AX_ATTACHMENT_URL_PREFIX.length);
134	  if (id.length === 0) return null;
135	  return { attachmentId: id };
136	}
137	
138	/** Convert one AI-SDK UIMessage's parts list to an AX ContentBlock array.
139	 *  Phase 3: ax://attachment/<id> file parts become attachment_ref blocks;
140	 *  other file parts fall back to text mentions (legacy behavior preserved
141	 *  for any non-ax adapter that might surface a file part in the future).
142	 */
143	function toContentBlocks(msg: UIMessage): ContentBlock[] {
144	  const blocks: ContentBlock[] = [];
145	  if (!msg.parts) return blocks;
146	
147	  // Collect text first (chat-flow concatenates all text into one block).
148	  let collectedText = '';
149	  for (const p of msg.parts) {
150	    if (p.type === 'text') {
151	      collectedText += p.text;
152	    }
153	  }
154	  if (collectedText.length > 0) {
155	    blocks.push({ type: 'text', text: collectedText });
156	  }
157	
158	  // Then file parts, preserving order.
159	  for (const p of msg.parts) {
160	    if (p.type !== 'file') continue;
161	    const ax = isAxAttachmentPart(p);
162	    if (ax !== null) {
163	      blocks.push({ type: 'attachment_ref', attachmentId: ax.attachmentId });
164	      continue;
165	    }
166	    // Non-ax file part — text-mention fallback (preserves the legacy
167	    // path so a future adapter that emits e.g. https:// file parts
168	    // doesn't drop the user's intent silently).
169	    const fp = p as { url?: string; mediaType?: string; filename?: string };
170	    const ref = fp.url ?? '';
171	    const filename = fp.filename ?? '';
172	    blocks.push({
173	      type: 'text',
174	      text: `[attachment: ${filename || ref}]`,
175	    });
176	  }
177	  return blocks;
178	}
179	
180	/** Test-only export of toContentBlocks so unit tests can drive it
181	 *  without booting an entire transport instance. */
182	export const toContentBlocksForTesting = toContentBlocks;
183	
184	/**
185	 * Body shape we POST. The server's `PostMessageRequest` zod schema is
186	 * the authority — we duck-type against it here to avoid importing the
187	 * server module from the React bundle (Invariant I2).
188	 */
189	interface PostBody {
190	  conversationId: string | null;
191	  agentId: string;
192	  contentBlocks: ContentBlock[];
193	}
194	
195	interface PostResponse {
196	  conversationId: string;
197	  reqId: string;
198	}
199	
200	export class AxChatTransport extends HttpChatTransport<UIMessage> {
201	  private readonly streamApi: string;
202	  private readonly fetchImpl: typeof fetch;
203	  private readonly getConversationIdFn: (() => string | null) | undefined;
204	  private readonly setConversationIdFn: ((id: string) => void) | undefined;
205	  private readonly getAgentIdFn: (() => string | null) | undefined;
206	
207	  /**
208	   * Local fallback for the conversation id when the caller hasn't wired
209	   * a `getConversationId` resolver. Persists across `sendMessages` calls
210	   * so a follow-up turn re-uses the conversation the server minted on
211	   * the first turn.
212	   */
213	  private localConversationId: string | null = null;
214	
215	  constructor(opts: AxChatTransportOptions = {}) {
216	    super({
217	      api: opts.api ?? '/api/chat/messages',
218	      // We override sendMessages below, so prepareSendMessagesRequest is
219	      // unused on the happy path. Provide a no-op body so HttpChatTransport
220	      // can still construct itself if a subclass call slips through.
221	      prepareSendMessagesRequest: async () => ({ body: {} }),
222	    });
223	    this.streamApi = opts.streamApi ?? '/api/chat/stream';
224	    // Bind to globalThis so the stored reference doesn't lose its Window
225	    // receiver. Calling `this.fetchImpl(...)` with `this === transport`
226	    // would otherwise throw `TypeError: Illegal invocation` in the browser.
227	    this.fetchImpl = opts.fetch ?? globalThis.fetch.bind(globalThis);
228	    this.getConversationIdFn = opts.getConversationId;
229	    this.setConversationIdFn = opts.setConversationId;
230	    this.getAgentIdFn = opts.getAgentId;
231	    // user opt is accepted for backward-compat with runtime.tsx callers
232	    // but unused on the AX wire (auth lives in cookies, not the body).
233	    void opts.user;
234	    void DEFAULT_USER;
235	  }
236	
237	  /**
238	   * Override the AI SDK's `sendMessages` to drive the two-phase flow:
239	   *  1. POST /api/chat/messages with the latest user turn → mint reqId.
240	   *  2. fetch the SSE stream at /api/chat/stream/:reqId and feed it
241	   *     through `processResponseStream`.
242	   */
243	  override async sendMessages(
244	    options: Parameters<HttpChatTransport<UIMessage>['sendMessages']>[0],
245	  ): Promise<ReadableStream<UIMessageChunk>> {
246	    const { messages, abortSignal } = options;
247	
248	    // Pull the latest user message — that's the one we POST. Earlier
249	    // turns are already persisted in the conversation row (Task 9 appends
250	    // user turns BEFORE agent:invoke; Task 15's runner replays history at
251	    // boot). We don't re-send them.
252	    const last = messages[messages.length - 1];
253	    if (!last || last.role !== 'user') {
254	      // Defensive — without a fresh user message there's nothing to send.
255	      // Return an empty stream that emits a finish so the runtime doesn't
256	      // hang waiting for a response.
257	      return makeEmptyFinishStream();
258	    }
259	
260	    // When a resolver is wired, it owns the answer — `null` from the
261	    // resolver explicitly means "no active conversation, server should
262	    // mint a new one" and must NOT fall through to the stale
263	    // localConversationId backup. The `?? localConversationId`
264	    // short-circuit only kicks in when no resolver is configured at
265	    // all (transport used standalone, e.g. in unit tests).
266	    const conversationId = this.getConversationIdFn
267	      ? this.getConversationIdFn()
268	      : this.localConversationId;
269	    const agentId = this.getAgentIdFn?.() ?? '';
270	    if (!agentId) {
271	      throw new Error('AxChatTransport: agentId is required');
272	    }
273	    const contentBlocks = toContentBlocks(last);
274	    if (contentBlocks.length === 0) {
275	      // No text to send — likely an upload-only message that we don't yet
276	      // serialize through the wire. Surface as a no-op finish.
277	      return makeEmptyFinishStream();
278	    }
279	
280	    const postBody: PostBody = { conversationId, agentId, contentBlocks };
281	
282	    // Phase 1: POST. The body cap (1 MiB) is enforced by http-server; if
283	    // the user pasted something gigantic it'll come back as 413. We let
284	    // the AI SDK surface the error to the chat hook's onError callback.
285	    const postInit: RequestInit = {
286	      method: 'POST',
287	      headers: {
288	        'content-type': 'application/json',
289	        // CSRF: the host's CSRF subscriber accepts the literal value
290	        // `ax-admin` for X-Requested-With OR a same-Origin request. The
291	        // exact value is the contract (see @ax/http-server csrf.ts);
292	        // browsers can't set custom headers on cross-origin simple
293	        // requests without a CORS preflight, so any non-attacker caller
294	        // can supply it.
295	        'x-requested-with': 'ax-admin',
296	      },
297	      body: JSON.stringify(postBody),
298	      credentials: 'include',
299	    };
300	    if (abortSignal) postInit.signal = abortSignal;
301	    const postResp = await this.fetchImpl(this.api, postInit);
302	    if (!postResp.ok) {
303	      throw new Error(
304	        `chat-flow POST failed: ${postResp.status} ${postResp.statusText}`,
305	      );
306	    }
307	    const postOut = (await postResp.json()) as PostResponse;
308	    if (!postOut.reqId || !postOut.conversationId) {
309	      throw new Error('chat-flow POST returned malformed response');
310	    }
311	    // Capture the conversationId so subsequent turns re-use it (and the
312	    // history adapter can hydrate from it on next mount).
313	    this.localConversationId = postOut.conversationId;
314	    this.setConversationIdFn?.(postOut.conversationId);
315	
316	    // Phase 2: SSE. We use fetch (not EventSource) so we can pass through
317	    // credentials, AbortSignal, and the AI SDK's existing
318	    // `processResponseStream` plumbing.
319	    const sseInit: RequestInit = {
320	      method: 'GET',
321	      headers: { accept: 'text/event-stream' },
322	      credentials: 'include',
323	    };
324	    if (abortSignal) sseInit.signal = abortSignal;
325	    const sseResp = await this.fetchImpl(
326	      `${this.streamApi}/${encodeURIComponent(postOut.reqId)}`,
327	      sseInit,
328	    );
329	    if (!sseResp.ok || !sseResp.body) {
330	      throw new Error(
331	        `chat-flow SSE open failed: ${sseResp.status} ${sseResp.statusText}`,
332	      );
333	    }
334	    return this.processResponseStream(sseResp.body);
335	  }
336	
337	  /**
338	   * Parse the AX SSE stream. Each `data:` line is a JSON `SseFrame`.
339	   * Lines split across decoder chunks are stitched via a `carry` buffer.
340	   *
341	   * Emission policy:
342	   *   - text-kind chunk → text-delta under id `text-N` (a new id is
343	   *     started after each thinking interlude so the renderer can split).
344	   *   - thinking-kind chunk → text-delta under id `thinking-N`. Whether
345	   *     the renderer SHOWS thinking parts is a UI decision (Task 21's
346	   *     toggle); the transport always emits, the UI hides by default.
347	   *   - phase frame → side-channel: drives `agentStatusActions.set(label)`
348	   *     directly. Phases are out-of-band agent-state metadata, not
349	   *     message content, so they intentionally bypass the AI-SDK chunk
350	   *     pipeline (the runtime's "running" state already drives the
351	   *     row's visibility; phases just relabel it). On the first content
352	   *     chunk we swap back to "Thinking…" — phases are pre-content only.
353	   *   - done frame → close any open part, emit `finish`.
354	   *   - stream close (no done frame) → same finish posture.
355	   */
356	  protected processResponseStream(
357	    stream: ReadableStream<Uint8Array>,
358	  ): ReadableStream<UIMessageChunk> {
359	    let textCounter = 0;
360	    let thinkingCounter = 0;
361	    let openText: string | null = null; // active text-N id
362	    let openThinking: string | null = null; // active thinking-N id
363	    let finished = false;
364	    let carry = '';
365	    /** True once any text/thinking chunk has arrived. After that we
366	     *  stop relabeling the status row from phase frames (phases are
367	     *  pre-content only) and we restore the "Thinking…" label exactly
368	     *  once. */
369	    let contentSeen = false;
370	
371	    const closeOpen = (controller: TransformStreamDefaultController<UIMessageChunk>): void => {
372	      if (openText !== null) {
373	        controller.enqueue({ type: 'text-end', id: openText });
374	        openText = null;
375	      }
376	      if (openThinking !== null) {
377	        controller.enqueue({ type: 'text-end', id: openThinking });
378	        openThinking = null;
379	      }
380	    };
381	
382	    const ensureOpenForKind = (
383	      kind: 'text' | 'thinking',
384	      controller: TransformStreamDefaultController<UIMessageChunk>,
385	    ): string => {
386	      if (kind === 'text') {
387	        // Switching from thinking → text closes the thinking part.
388	        if (openThinking !== null) {
389	          controller.enqueue({ type: 'text-end', id: openThinking });
390	          openThinking = null;
391	        }
392	        if (openText === null) {
393	          openText = `text-${textCounter}`;
394	          textCounter++;
395	          controller.enqueue({ type: 'text-start', id: openText });
396	        }
397	        return openText;
398	      }
399	      // thinking
400	      if (openText !== null) {
401	        controller.enqueue({ type: 'text-end', id: openText });
402	        openText = null;
403	      }
404	      if (openThinking === null) {
405	        openThinking = `thinking-${thinkingCounter}`;
406	        thinkingCounter++;
407	        controller.enqueue({
408	          type: 'text-start',
409	          id: openThinking,
410	          providerMetadata: { ax: { thinking: true } },
411	        });
412	      }
413	      return openThinking;
414	    };
415	
416	    return stream
417	      .pipeThrough(new TextDecoderStream() as ReadableWritablePair<string, Uint8Array>)
418	      .pipeThrough(
419	        new TransformStream<string, UIMessageChunk>({
420	          transform(rawChunk, controller) {
421	            if (finished) return;
422	            const data = carry + rawChunk;
423	            const lines = data.split('\n');
424	            // Last element may be incomplete — carry it to the next chunk.
425	            carry = lines.pop() ?? '';
426	
427	            for (const line of lines) {
428	              const trimmed = line.trim();
429	              if (!trimmed || trimmed.startsWith(':')) continue;
430	              if (!trimmed.startsWith('data: ')) continue;
431	
432	              let frame: SseFrame;
433	              try {
434	                frame = JSON.parse(trimmed.slice(6)) as SseFrame;
435	              } catch {
436	                // Malformed JSON — skip. Server is the source of truth;
437	                // a bad frame is a bug there, not here.
438	                continue;
439	              }
440	
441	              if ('done' in frame && frame.done === true) {
442	                closeOpen(controller);
443	                controller.enqueue({ type: 'finish', finishReason: 'stop' });
444	                finished = true;
445	                return;
446	              }
447	              // phase frame — out-of-band; drives the status row directly.
448	              if ('phase' in frame && typeof frame.phase === 'string') {
449	                if (contentSeen) continue; // pre-content only
450	                const label = PHASE_LABELS[frame.phase];
451	                if (label !== undefined) {
452	                  agentStatusActions.set(label);
453	                }
454	                continue;
455	              }
456	              // text/thinking chunk
457	              if (
458	                'kind' in frame &&
459	                (frame.kind === 'text' || frame.kind === 'thinking')
460	              ) {
461	                if (!contentSeen) {
462	                  contentSeen = true;
463	                  // Restore the default working label so the cleanup
464	                  // posture (RunningEffect in AgentStatus.tsx) hides on
465	                  // turn end. Without this swap, a turn that ran with a
466	                  // phase would leave the row stuck on the phase label
467	                  // while the "Thinking…"-keyed cleanup never fires.
468	                  agentStatusActions.set('Thinking…');
469	                }
470	                const id = ensureOpenForKind(frame.kind, controller);
471	                controller.enqueue({
472	                  type: 'text-delta',
473	                  id,
474	                  delta: frame.text,
475	                  ...(frame.kind === 'thinking'
476	                    ? { providerMetadata: { ax: { thinking: true } } }
477	                    : {}),
478	                });
479	                continue;
480	              }
481	              // tool-use frame: model issued a tool call. Close any open
482	              // text/thinking part first — assistant-ui's MessageRepository
483	              // expects parts to come in ordered. Then emit the AI SDK v5
484	              // `tool-input-available` chunk which assistant-ui's
485	              // react-ai-sdk bridge converts to a tool-call ThreadMessage
486	              // part rendered by Thread.tsx via ToolGroup + ToolFallback.
487	              if ('kind' in frame && frame.kind === 'tool-use') {
488	                if (!contentSeen) {
489	                  contentSeen = true;
490	                  agentStatusActions.set('Thinking…');
491	                }
492	                closeOpen(controller);
493	                controller.enqueue({
494	                  type: 'tool-input-available',
495	                  toolCallId: frame.toolCallId,
496	                  toolName: frame.toolName,
497	                  input: frame.input,
498	                  dynamic: true,
499	                });
500	                continue;
501	              }
502	              // tool-result frame: the tool finished. Pair to the prior
503	              // tool-use by toolCallId; AI SDK threads the output into the
504	              // existing tool-call part and flips its state to
505	              // `output-available` (or `output-error`).
506	              if ('kind' in frame && frame.kind === 'tool-result') {
507	                // Replay can attach mid-turn at a result chunk (no preceding
508	                // text/thinking/tool-use). Flip contentSeen so subsequent
509	                // phase frames don't think we're still pre-content.
510	                if (!contentSeen) {
511	                  contentSeen = true;
512	                  agentStatusActions.set('Thinking…');
513	                }
514	                if (frame.isError === true) {
515	                  controller.enqueue({
516	                    type: 'tool-output-error',
517	                    toolCallId: frame.toolCallId,
518	                    errorText: frame.output || 'tool failed',
519	                    dynamic: true,
520	                  });
521	                } else {
522	                  controller.enqueue({
523	                    type: 'tool-output-available',
524	                    toolCallId: frame.toolCallId,
525	                    output: frame.output,
526	                    dynamic: true,
527	                  });
528	                }
529	                continue;
530	              }
531	            }
532	          },
533	          flush(controller) {
534	            if (finished) return;
535	            // Stream closed without an explicit done frame — close any
536	            // open parts and synthesize a finish so the runtime returns
537	            // to ready state instead of hanging.
538	            closeOpen(controller);
539	            controller.enqueue({ type: 'finish', finishReason: 'stop' });
540	            finished = true;
541	          },
542	        }),
543	      );
