548	 * Build a no-op stream that emits `finish` and closes immediately.
549	 * Used when sendMessages is called without a usable user-message
550	 * payload (e.g., empty composer flush). Returning a real ReadableStream
551	 * keeps the AI SDK's chat hook on the happy path.
552	 */
553	function makeEmptyFinishStream(): ReadableStream<UIMessageChunk> {
554	  return new ReadableStream<UIMessageChunk>({
555	    start(controller) {
