437	// ---------------------------------------------------------------------------
438	// Orchestrator instance. One Map-keyed-by-sessionId for in-flight waiters:
439	// chat:end subscriber looks up the session and resolves its deferred with
440	// the runner-emitted outcome. Keyed by sessionId (not reqId) because the
441	// IPC server's per-request ctx is built from the token → session lookup and
442	// carries the SAME sessionId that the orchestrator minted — that's the
443	// stable join key across the host ⇄ runner boundary.
444	// ---------------------------------------------------------------------------
445	
446	export const PLUGIN_NAME = '@ax/chat-orchestrator';
447	const DEFAULT_CHAT_TIMEOUT_MS = 10 * 60 * 1000;
448	
449	export function createOrchestrator(
450	  bus: HookBus,
451	  config: ChatOrchestratorConfig,
452	): {
453	  runAgentInvoke(ctx: AgentContext, input: AgentInvokeInput): Promise<AgentOutcome>;
454	  onChatEnd(ctx: AgentContext, payload: { outcome: AgentOutcome }): void;
455	  onTurnEnd(ctx: AgentContext, payload?: { reqId?: string }): void;
456	} {
457	  // Waiters are tracked by ctx.reqId (server-minted, J9, unique per
458	  // agent:invoke). On the J6 routed path, two concurrent agent:invokes for the
459	  // same conversation share a sessionId — keying by sessionId would let
460	  // the second agent:invoke overwrite the first's waiter (causing the first
461	  // to time out and the second to resolve with the wrong outcome).
462	  //
463	  // Resolution paths:
464	  //   - chat:end fired by the orchestrator itself (error paths) carries
465	  //     the agent:invoke ctx → ctx.reqId matches directly.
466	  //   - chat:end fired by the IPC server (runner POSTs /event.chat-end)
467	  //     stamps a fresh per-request ctx.reqId, so the reqId lookup
468	  //     misses. We fall back via `reqIdsBySession`: when only one
469	  //     waiter exists for a given sessionId, resolve THAT waiter; when
470	  //     multiple exist (the routed-collision case), the reqId-keyed
471	  //     entry from the orchestrator self-fire wins. The fresh-spawn
472	  //     path always has exactly one waiter per sessionId.
473	  const waitersByReqId = new Map<string, Deferred<AgentOutcome>>();
474	  const reqIdsBySession = new Map<string, Set<string>>();
475	  function registerWaiter(
476	    sessionId: string,
477	    reqId: string,
478	    deferred: Deferred<AgentOutcome>,
479	  ): void {
480	    waitersByReqId.set(reqId, deferred);
481	    let set = reqIdsBySession.get(sessionId);
482	    if (set === undefined) {
483	      set = new Set();
