import type { AgentOutcome, Plugin } from '@ax/core';
import {
  createOrchestrator,
  PLUGIN_NAME,
  type ChatOrchestratorConfig,
  type AgentInvokeInput,
} from './orchestrator.js';

// ---------------------------------------------------------------------------
// @ax/chat-orchestrator plugin
//
// Registers `agent:invoke` — the host-side entrypoint a CLI (or any other host)
// uses to drive a single user→agent turn-sequence. Subscribes to `chat:end`
// so the orchestrator can capture the outcome the runner emits via its
// /event.chat-end IPC POST.
//
// Everything spicy happens inside `createOrchestrator`; this file is just
// the manifest + hook registration.
// ---------------------------------------------------------------------------

export function createChatOrchestratorPlugin(
  config: ChatOrchestratorConfig,
): Plugin {
  return {
    manifest: {
      name: PLUGIN_NAME,
      version: '0.0.0',
      registers: ['agent:invoke'],
      // The orchestrator drives the per-chat lifecycle by calling these
      // peers. `session:create` is NOT listed — sandbox:open-session mints
      // the session itself; a double-create throws duplicate-session. The
      // orchestrator intentionally delegates session minting to the sandbox
      // plugin. `ipc:stop` is NOT listed either: sandbox-subprocess stops
      // its own per-session listener on child-close (no host-side caller
      // needed), and the k8s preset uses @ax/ipc-http which has a
      // process-scoped listener with no per-session start/stop hooks.
      //
      // `agents:resolve` is a HARD dep as of Week 9.5 — every chat goes
      // through the ACL gate before the sandbox is spawned. This forces
      // any preset that wires the orchestrator to also wire @ax/agents,
      // which is the intended coupling.
      calls: [
        'session:queue-work',
        'session:terminate',
        'sandbox:open-session',
        'agents:resolve',
      ],
      // ----- conditionally-called peers (NOT in `calls`) -----
      //
      // Week 10–12 Task 16 (J6) introduces `conversations:get`,
      // `conversations:bind-session`, and `session:is-alive`. The
      // orchestrator dispatches these ONLY when `ctx.conversationId` is
      // set — i.e. on the channel-web path that ALSO loads
      // @ax/conversations + a session backend with the new hook. Plugins
      // outside that path (CLI canary, mcp-client e2e harness) drive the
      // orchestrator without a conversation context, so they don't need
      // the peers loaded.
      //
      // Phase 2B adds `system-prompt:augment` to this same category. The
      // hook is registered by @ax/memory-strata (auto-inject path) and any
      // future personalization / tenant-policy provider. Listing it in
      // `calls` would force every preset wiring the orchestrator to also
      // wire a provider — but the CLI canary, the single-tenant preset,
      // and any deploy that doesn't load memory-strata MUST stay functional
      // without one. The orchestrator gates with `bus.hasService(...)` and
      // no-ops when absent.
      //
      // We gate each call with `bus.hasService(...)` at runtime to keep
      // the orchestrator usable in those non-channel-web presets. Failing
      // closed (no routing, no bind) is the correct degraded behavior —
      // a missing conversations plugin can't keep state about active
      // sessions anyway.
      //
      // Same pattern as the existing `ipc:stop` non-declaration: when a
      // hook is conditionally consumed, we don't declare it.
      // We listen to `chat:end` to capture the outcome emitted by the
      // runner (via the IPC server's /event.chat-end handler). The
      // subscriber is a pass-through: resolves the waiting deferred,
      // returns undefined, doesn't veto and doesn't transform.
      //
      // We also listen to `chat:turn-end` so that in one-shot mode
      // (the default for 6.5a) we queue a `cancel` into the runner's
      // inbox after the first user message completes — the runner is
      // persistent by design, so without this signal it would block
      // forever on inbox.next() and the agent:invoke would time out.
      subscribes: ['chat:end', 'chat:turn-end'],
    },
    init({ bus }) {
      const orch = createOrchestrator(bus, config);

      bus.registerService<AgentInvokeInput, AgentOutcome>(
        'agent:invoke',
        PLUGIN_NAME,
        async (ctx, input) => orch.runAgentInvoke(ctx, input),
      );

      bus.subscribe<{ outcome: AgentOutcome }>(
        'chat:end',
        PLUGIN_NAME,
        async (ctx, payload) => {
          orch.onChatEnd(ctx, payload);
          return undefined; // pass-through; no transform, no veto.
        },
      );

      bus.subscribe<{ reason?: string; reqId?: string }>(
        'chat:turn-end',
        PLUGIN_NAME,
        async (ctx, payload) => {
          orch.onTurnEnd(ctx, payload);
          return undefined;
        },
      );
    },
  };
}

import {
  makeAgentContext,
  type AgentContext,
  type HookBus,
  type Plugin,
} from '@ax/core';
import { createChunkBuffer, type ChunkBuffer } from './chunk-buffer.js';
import { registerAttachmentsRoutes } from './routes-attachments.js';
import { registerChatRoutes } from './routes-chat.js';
import {
  createBufferFillSubscriber,
  createPhaseFillSubscriber,
  createSseHandler,
  createTurnEndEvictor,
  type RouteRequest,
  type RouteResponse,
} from './sse.js';
import { createTitleEventsHandler } from './title-events.js';
import type { PhaseEvent, StreamChunk } from './types.js';

const PLUGIN_NAME = '@ax/channel-web';

// ---------------------------------------------------------------------------
// @ax/channel-web host-side plugin shell.
//
// Today: registers GET /api/chat/stream/:reqId for browser SSE consumers
// (Task 7 of Week 10–12). Tasks 9–13 extend this same plugin with the
// rest of the /api/chat/* surface (POST messages, GET conversations, etc.)
// — those slices land here so channel-web's wire surface stays in one
// place.
//
// Single-replica only (J8). Multi-replica fan-out is a Week 13+ slice
// that swaps the in-process chunk buffer for a redis stream / pg
// logical replication path; the SSE handler stays the same.
//
// Manifest:
//   - registers: nothing (the API surface is HTTP routes, not bus hooks).
//   - calls: http:register-route, auth:require-user, agents:resolve,
//     agents:list-for-user, conversations:get-by-req-id,
//     conversations:create / :get / :list / :delete,
//     agent:invoke. All hard — the chat-flow surface can't function without
//     any of them.
//   - subscribes: chat:stream-chunk (fills the buffer + per-connection
//     filter), chat:phase (single-slot phase memory + per-connection
//     filter), chat:turn-end (host-side eviction so the buffer doesn't
//     grow unbounded for streams nobody listens to).
// ---------------------------------------------------------------------------

// eslint-disable-next-line @typescript-eslint/no-empty-object-type
export interface ChannelWebServerConfig {}

export function createChannelWebServerPlugin(
  _config: ChannelWebServerConfig = {},
): Plugin {
  let buffer: ChunkBuffer | undefined;
  const unregisterRoutes: Array<() => void> = [];
  let busRef: HookBus | undefined;

  return {
    manifest: {
      name: PLUGIN_NAME,
      version: '0.0.0',
      registers: [],
      calls: [
        'http:register-route',
        'auth:require-user',
        'agents:resolve',
        'agents:list-for-user',
        'conversations:get-by-req-id',
        'conversations:create',
        'conversations:get',
        'conversations:list',
        'conversations:delete',
        'agent:invoke',
        // Phase 3 — attachments & artifacts.
        'attachments:store-temp',
        'attachments:commit',
        'attachments:download',
      ],
      subscribes: ['chat:stream-chunk', 'chat:phase', 'chat:turn-end', 'conversations:title-updated'],
    },

    async init({ bus }) {
      busRef = bus;
      const initCtx: AgentContext = makeAgentContext({
        sessionId: 'init',
        agentId: PLUGIN_NAME,
        userId: 'system',
      });

      const localBuffer = createChunkBuffer();
      buffer = localBuffer;

      // Buffer-fill subscriber — host-side, captures every chunk
      // regardless of whether anyone's listening yet. Without this,
      // the SSE handler's `tail()` replay would always be empty.
      bus.subscribe<StreamChunk>(
        'chat:stream-chunk',
        `${PLUGIN_NAME}/buffer-fill`,
        createBufferFillSubscriber(localBuffer),
      );

      // Phase-fill subscriber — same role as buffer-fill but for the
      // single-slot phase memory. Without this, an SSE consumer that
      // attaches after sandbox-k8s fires `chat:phase` would never see
      // the "Starting sandbox…" label.
      bus.subscribe<PhaseEvent>(
        'chat:phase',
        `${PLUGIN_NAME}/phase-fill`,
        createPhaseFillSubscriber(localBuffer),
      );

      // Turn-end evictor — pre-cleans the buffer for terminated turns
      // so the per-connection turn-end subscriber doesn't have to be
      // present for the buffer to drain.
      bus.subscribe<{ reqId?: string }>(
        'chat:turn-end',
        `${PLUGIN_NAME}/turn-end-evictor`,
        createTurnEndEvictor(localBuffer),
      );

      const handler = createSseHandler({
        bus,
        initCtx,
        buffer: localBuffer,
      });

      const routeResult = await bus.call<
        unknown,
        { unregister: () => void }
      >('http:register-route', initCtx, {
        method: 'GET',
        path: '/api/chat/stream/:reqId',
        // The http-server's HttpRequest/HttpResponse are the canonical
        // shapes; our duck-typed RouteRequest/RouteResponse are a
        // structural subset (Invariant I2 — no @ax/http-server import in
        // sse.ts). Cast through `unknown` because exactOptionalProperty-
        // Types treats the structural intersection differently than the
        // `HttpRouteHandler` parameter declaration.
        handler: handler as unknown as (
          req: RouteRequest,
          res: RouteResponse,
        ) => Promise<void>,
      });
      unregisterRoutes.push(routeResult.unregister);

      // Live title push — per-user SSE. Surfaces a title that lands after
      // the client's poll window without a reload (design I5: ships with
      // its consumer in the same PR; the route auto-registers here, no
      // preset change needed).
      const titleEventsHandler = createTitleEventsHandler({ bus, initCtx });
      const titleEventsRoute = await bus.call<
        unknown,
        { unregister: () => void }
      >('http:register-route', initCtx, {
        method: 'GET',
        path: '/api/chat/title-events',
        handler: titleEventsHandler as unknown as (
          req: RouteRequest,
          res: RouteResponse,
        ) => Promise<void>,
      });
      unregisterRoutes.push(titleEventsRoute.unregister);

      // Tasks 9-13 — chat-flow REST surface (POST messages, GET/DELETE
      // conversations, GET conversations/:id, GET agents). CSRF gated
      // automatically by @ax/http-server's subscriber on state-changing
      // methods. See routes-chat.ts for per-endpoint details.
      const chatRouteUnregisters = await registerChatRoutes(bus, initCtx);
      for (const u of chatRouteUnregisters) unregisterRoutes.push(u);

      // Phase 3 — attachments + downloads. Closes the half-wired window
      // opened in Phase 1 (routes-chat.ts already calls
      // `attachments:commit` for attachment_ref blocks); declaring the
      // three hooks in `manifest.calls` + registering the two routes here
      // makes the surface complete.
      const attachmentRouteUnregisters = await registerAttachmentsRoutes(
        bus,
        initCtx,
      );
      for (const u of attachmentRouteUnregisters) unregisterRoutes.push(u);
    },

    async shutdown() {
      // Drop the route first so a re-init doesn't hit duplicate-route.
      while (unregisterRoutes.length > 0) {
        const fn = unregisterRoutes.pop();
        try {
          fn?.();
        } catch {
          // best-effort
        }
      }
      // Drop our subscribers so a re-init in tests doesn't leave the
      // old buffer-fill closure ALONGSIDE the new one.
      busRef?.unsubscribe('chat:stream-chunk', `${PLUGIN_NAME}/buffer-fill`);
      busRef?.unsubscribe('chat:phase', `${PLUGIN_NAME}/phase-fill`);
      busRef?.unsubscribe(
        'chat:turn-end',
        `${PLUGIN_NAME}/turn-end-evictor`,
      );
      busRef = undefined;
      // Stop the chunk buffer's sweep timer.
      buffer?.dispose();
      buffer = undefined;
    },
  };
}

