59	      captured.ended = true;
60	    },
61	    text(s) {
62	      captured.textBody = s;
63	      captured.ended = true;
64	    },
65	    end() {
66	      captured.ended = true;
67	    },
68	    stream() {
69	      stream = {
70	        write(chunk) {
71	          if (captured.streamClosed) return;
72	          captured.streamWrites.push(
73	            typeof chunk === 'string' ? chunk : chunk.toString('utf8'),
74	          );
75	        },
76	        close() {
77	          captured.streamClosed = true;
78	          for (const h of onCloseHandlers.splice(0)) h();
79	        },
80	        onClose(handler) {
81	          if (captured.streamClosed) {
82	            queueMicrotask(handler);
83	            return;
84	          }
85	          onCloseHandlers.push(handler);
86	        },
87	      };
88	      captured.ended = true;
89	      return stream;
90	    },
91	  };
92	  captured.fireClientClose = () => {
93	    if (captured.streamClosed) return;
94	    captured.streamClosed = true;
95	    for (const h of onCloseHandlers.splice(0)) h();
96	  };
97	  return { res, captured };
98	}
