        unknown,
        { unregister: () => void }
      >('http:register-route', initCtx, {
        method: 'GET',
        path: '/api/chat/title-events',
        handler: titleEventsHandler as unknown as (
          req: RouteRequest,
          res: RouteResponse,
        ) => Promise<void>,
      });
      unregisterRoutes.push(titleEventsRoute.unregister);

