11	} from '@ax/core';
12	import { createTestHarness } from '@ax/test-harness';
13	import { createChatOrchestratorPlugin } from '../index.js';
14	
15	// Default agent stub — every test gets its own copy via spread to avoid
16	// accidental mutation. Mirrors @ax/agents' AgentRecord shape (the
17	// orchestrator duplicates it locally per I2).
18	const TEST_AGENT = {
19	  id: 'test-agent',
20	  ownerId: 'test-user',
21	  ownerType: 'user' as const,
22	  visibility: 'personal' as const,
23	  displayName: 'Test',
24	  systemPrompt: 'be helpful',
25	  allowedTools: ['file.read'],
26	  mcpConfigIds: [],
27	  model: 'claude-sonnet-4-7',
28	  workspaceRef: null,
29	};
30	
31	// ---------------------------------------------------------------------------
32	// Orchestrator tests
33	//
34	// We exercise agent:invoke end-to-end through the bus, but stub the three peer
35	// plugins (session / sandbox / ipc) as service-hook mocks so no real runner
36	// subprocess is spawned. The mock `sandbox:open-session` simulates what a
37	// real runner would do: it fires `chat:end` on the bus (standing in for the
38	// IPC server's /event.chat-end handler) with a constructed outcome, and
39	// returns a handle with `kill()` + `exited` promises.
40	//
41	// The sessionId the orchestrator passes to `sandbox:open-session` is the
42	// same sessionId that flows through every chat:end fire — that's the join
43	// key the orchestrator uses in its waiter Map.
44	// ---------------------------------------------------------------------------
45	
46	function silentCtx(sessionId = 'test-session') {
47	  return makeAgentContext({
48	    sessionId,
49	    agentId: 'test-agent',
50	    userId: 'test-user',
51	    logger: createLogger({ reqId: 'orch-test', writer: () => undefined }),
52	  });
53	}
54	
55	interface MockBundle {
56	  services: Record<string, ServiceHandler>;
57	  calls: {
58	    sessionQueueWork: number;
59	    sessionTerminate: number;
60	    sandboxOpen: number;
61	    killCalls: number;
62	    agentsResolve: number;
63	    lastSandboxInput: unknown;
64	  };
65	  lastQueuedMessage(): AgentMessage | undefined;
66	}
67	
68	// Builds a default mock bundle. Callers can override individual services.
69	// The orchestrator itself does NOT call session:create (sandbox:open-session
70	// does), so we don't mock session:create here. agents:resolve IS mocked
71	// because Week 9.5's orchestrator hard-depends on it.
72	function buildMocks(opts: {
73	  openSession?: ServiceHandler;
74	  queueWork?: ServiceHandler;
75	  agentsResolve?: ServiceHandler;
76	  /**
77	   * Phase 6: credential-proxy is mandatory — the orchestrator now refuses
78	   * to open a sandbox if neither `proxy:open-session` nor `proxy:close-
79	   * session` is registered, returning `proxy-not-loaded`. To keep tests
80	   * that exercise the fresh-sandbox path working without forcing every
81	   * caller to wire `buildProxyHooks()`, we register trivial proxy stubs
82	   * by default. Tests that specifically want to assert the missing-proxy
83	   * gate set `omitProxyStubs: true` to exclude them.
84	   */
85	  omitProxyStubs?: boolean;
86	} = {}): MockBundle {
87	  const calls = {
88	    sessionQueueWork: 0,
89	    sessionTerminate: 0,
90	    sandboxOpen: 0,
91	    killCalls: 0,
92	    agentsResolve: 0,
93	    lastSandboxInput: undefined as unknown,
94	  };
95	  let lastQueued: AgentMessage | undefined;
96	
97	  const services: Record<string, ServiceHandler> = {
98	    'agents:resolve': async (ctx, input) => {
99	      calls.agentsResolve += 1;
100	      if (opts.agentsResolve !== undefined) {
101	        return opts.agentsResolve(ctx, input);
102	      }
103	      return { agent: { ...TEST_AGENT } };
104	    },
105	    'session:queue-work':
106	      opts.queueWork ??
107	      (async (_ctx, input: unknown) => {
108	        calls.sessionQueueWork += 1;
109	        const entry = (input as { entry: { type: string; payload?: AgentMessage } })
110	          .entry;
111	        if (entry.type === 'user-message') {
112	          lastQueued = entry.payload;
113	        }
114	        return { cursor: 0 };
